Code:
public int countClumps(int[] nums) {
    int clumpCount = 0;
    boolean inClump = false;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == nums[i - 1]) {
            if (!inClump) {
                clumpCount++;
                inClump = true;
            }
        } else {
            inClump = false;
        }
    }
    return clumpCount;
}

